#include <iostream>
using namespace std;

class Animal {
public:
    virtual void sound() {  // Virtual function
        cout << "Some animal sound" << endl;
    }
    virtual ~Animal() { cout << "Animal destructor" << endl; }  // Virtual destructor
};

class Dog : public Animal {
public:
    void sound() override {  // Override virtual function
        cout << "Dog barks: Woof! Woof!" << endl;
    }
    ~Dog() { cout << "Dog destructor" << endl; }
};

class Cat : public Animal {
public:
    void sound() override {
        cout << "Cat meows: Meow! Meow!" << endl;
    }
    ~Cat() { cout << "Cat destructor" << endl; }
};

int main() {
    // Base class pointers pointing to derived objects
    Animal* animals[3];
    animals[0] = new Animal();
    animals[1] = new Dog();
    animals[2] = new Cat();

    for (int i = 0; i < 3; i++) {
        animals[i]->sound();  // Runtime polymorphism
    }

    for (int i = 0; i < 3; i++) {
        delete animals[i];  // Proper cleanup with virtual destructor
    }

    return 0;
}

#include <iostream>
using namespace std;

class Shape {
protected:
    string name;
public:
    Shape(string n) : name(n) {}
    virtual double area() = 0;  // Pure virtual function
    virtual void display() {
        cout << "Shape: " << name << endl;
    }
    virtual ~Shape() {}
};

class Rectangle : public Shape {
private:
    double length, width;
public:
    Rectangle(double l, double w) : Shape("Rectangle"), length(l), width(w) {}
    double area() override {
        return length * width;
    }
};

class Circle : public Shape {
private:
    double radius;
public:
    Circle(double r) : Shape("Circle"), radius(r) {}
    double area() override {
        return 3.14159 * radius * radius;
    }
};

int main() {
    // Shape s;  // ERROR: Cannot instantiate abstract class
    Shape* shapes[2];  // Array of base class pointers

    shapes[0] = new Rectangle(5, 3);
    shapes[1] = new Circle(4);

    for (int i = 0; i < 2; i++) {
        cout << "Area: " << shapes[i]->area() << endl;
    }

    delete shapes[0];
    delete shapes[1];

    return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
    // Virtual destructor - important for polymorphism
    virtual ~Base() {
        cout << "Base destructor called" << endl;
    }
    virtual void show() {
        cout << "Base show" << endl;
    }
};

class Derived : public Base {
private:
    int* data;
public:
    Derived() {
        data = new int[100];  // Allocate memory
        cout << "Memory allocated in Derived" << endl;
    }

    ~Derived() override {
        delete[] data;  // Release memory
        cout << "Derived destructor called - memory freed" << endl;
    }

    void show() override {
        cout << "Derived show" << endl;
    }
};

int main() {
    Base* ptr = new Derived();
    ptr->show();  // Calls Derived::show()

    delete ptr;  // With virtual destructor: calls Derived then Base
    // Without virtual: only Base destructor - MEMORY LEAK!

    return 0;
}

class Animal:
    def sound(self):
        raise NotImplementedError("Subclasses must implement sound()")

class Dog(Animal):
    def sound(self):
        return "Woof! Woof!"

class Cat(Animal):
    def sound(self):
        return "Meow! Meow!"

def make_sound(animal):
    """Python uses duck typing - no need for explicit base pointer"""
    return animal.sound()

# Usage - Python handles polymorphism automatically
animals = [Dog(), Cat(), Dog()]
for animal in animals:
    print(make_sound(animal))

# Output:
# Woof! Woof!
# Meow! Meow!
# Woof! Woof!
